def process_data_job(payload):
    logging.info('Executing data processing job')
    data = payload.get('data', [])
    operation = payload.get('operation', 'transform')
    
    if operation == 'transform':
        result = [item * 2 if isinstance(item, (int, float)) else item for item in data]
        logging.info(f'Transformed {len(result)} items')
    elif operation == 'aggregate':
        if all(isinstance(x, (int, float)) for x in data):
            result = sum(data)
            logging.info(f'Aggregation result: {result}')
    elif operation == 'filter':
        condition = payload.get('condition', lambda x: True)
        result = [item for item in data if condition(item)]
        logging.info(f'Filtered to {len(result)} items')


def process_report_job(payload):
    logging.info('Executing report generation job')
    report_type = payload.get('report_type', 'summary')
    data_source = payload.get('data_source', {})
    parameters = payload.get('parameters', {})
    
    logging.info(f'Generating {report_type} report with parameters: {parameters}')
    
    report_data = {
        'report_type': report_type,
        'generated_at': datetime.utcnow().isoformat(),
        'record_count': len(data_source) if isinstance(data_source, list) else 0,
        'status': 'completed'
    }
    
    logging.info(f'Report generated: {report_data}')


def process_batch_job(payload):
    logging.info('Executing batch operation job')
    operations = payload.get('operations', [])
    batch_size = payload.get('batch_size', 100)
    
    for idx, operation in enumerate(operations):
        op_type = operation.get('type', 'unknown')
        op_data = operation.get('data', {})
        
        logging.info(f'Executing batch operation {idx + 1}/{len(operations)}: {op_type}')
        
        if op_type == 'insert':
            records = op_data.get('records', [])
            logging.info(f'Inserting {len(records)} records')
        elif op_type == 'update':
            records = op_data.get('records', [])
            logging.info(f'Updating {len(records)} records')
        elif op_type == 'delete':
            ids = op_data.get('ids', [])
            logging.info(f'Deleting {len(ids)} records')
    
    logging.info(f'Completed {len(operations)} batch operations')


class CustomJob:
    def __init__(self, job_name, parameters):
        self.job_name = job_name
        self.parameters = parameters
        self.status = 'pending'
    
    def execute(self):
        logging.info(f'Executing custom job: {self.job_name}')
        self.status = 'running'
        
        logging.info(f'Job parameters: {self.parameters}')
        
        self.status = 'completed'
        logging.info(f'Custom job {self.job_name} completed')
    
    def process(self):
        self.execute()